import boto3
import os
import logging

s3 = boto3.client('s3')
sns = boto3.client('sns')

logger = logging.getLogger()
logger.setLevel(logging.INFO)

def lambda_handler(event, context):
    # Extract bucket name and key from the event
    bucket_name = event['Records'][0]['s3']['bucket']['name']
    key = event['Records'][0]['s3']['object']['key']
    
    # Read image from S3
    try:
        logger.info(f"Reading image from S3 bucket: {bucket_name}, Key: {key}")
        response = s3.get_object(Bucket=bucket_name, Key=key)
        image_data = response['Body'].read()
        
        # Process image (Placeholder - implement image processing logic here)
        processed_image_data = image_data  # Replace this with actual image processing

        # Write processed image back to S3
        processed_key = f"processed/{key}"
        s3.put_object(Bucket=bucket_name, Key=processed_key, Body=processed_image_data)
        logger.info(f"Processed image saved to S3 bucket: {bucket_name}, Key: {processed_key}")
        
        # Send SNS notification
        topic_arn = os.environ['SNS_TOPIC_ARN']  # Retrieve the SNS topic ARN from environment variables
        message = f"Image processed successfully. Original key: {key}, Processed key: {processed_key}"
        sns.publish(TopicArn=topic_arn, Message=message)
        logger.info("SNS notification sent.")
        
    except Exception as e:
        logger.error(f"Error processing image: {e}")
        raise

